plugin.detectCode:
const t = input.trim();
const hasSection = /^\[[\w.]+\]$/m.test(t);
const hasKV = /^\w[\w.-]*\s*=\s*.+$/m.test(t);
return (hasKV || hasSection) ? 0.85 : 0;

plugin.executeCode:
const lines = input.split('\n');
const out = [];
let prevWasContent = false;
for (let i = 0; i < lines.length; i++) {
  const raw = lines[i];
  const trimmed = raw.trim();
  // Blank line
  if (!trimmed) {
    if (prevWasContent) out.push('');
    prevWasContent = false;
    continue;
  }
  // Comment: pass through
  if (trimmed.startsWith('#')) {
    out.push(trimmed);
    prevWasContent = true;
    continue;
  }
  // Section header: ensure blank line before (if not first)
  if (/^\[[^\[]]/.test(trimmed)) {
    if (out.length > 0 && out[out.length - 1] !== '') out.push('');
    out.push(trimmed);
    prevWasContent = true;
    continue;
  }
  // Array of tables
  if (trimmed.startsWith('[[')) {
    if (out.length > 0 && out[out.length - 1] !== '') out.push('');
    out.push(trimmed);
    prevWasContent = true;
    continue;
  }
  // Key = value: normalize spacing
  const eqIdx = trimmed.indexOf('=');
  if (eqIdx > 0) {
    const key = trimmed.slice(0, eqIdx).trimEnd();
    const val = trimmed.slice(eqIdx + 1).trimStart();
    out.push(`${key} = ${val}`);
    prevWasContent = true;
    continue;
  }
  out.push(trimmed);
  prevWasContent = true;
}
// Remove trailing blanks
while (out.length && !out[out.length - 1]) out.pop();
return { output: out.join('\n') + '\n', outputLanguage: 'toml' };
